use anyhow::{bail, Context, Result};
use opensession_core::session::{
    build_git_storage_meta_json_with_git, is_auxiliary_session, working_directory, GitMeta,
};
use opensession_core::sanitize::{sanitize_session, SanitizeConfig};
use std::path::Path;
use std::time::Duration;

use crate::config::{load_config, load_daemon_config};
use opensession_api_client::ApiClient;
use opensession_parsers::ParserRegistry;

/// Upload a session file to the configured server (or git branch with --git)
pub async fn run_upload(file: &Path, parent_ids: &[String], use_git: bool) -> Result<()> {
    if !file.exists() {
        bail!("File not found: {}", file.display());
    }

    let config = load_config()?;
    let daemon_config = load_daemon_config()?;

    // Find a parser that can handle this file
    let registry = ParserRegistry::default();
    let parser = registry.parser_for_path(file);

    let parser = match parser {
        Some(p) => p,
        None => bail!(
            "No parser found for file: {}\nSupported formats: Claude Code (.jsonl), Codex (.jsonl), OpenCode (.json), Cline, Amp, Cursor, Gemini",
            file.display()
        ),
    };

    println!("Parsing with {} parser...", parser.name());
    let session = parser
        .parse(file)
        .with_context(|| format!("Failed to parse {}", file.display()))?;
    if is_auxiliary_session(&session) {
        println!(
            "Skipping upload: auxiliary session '{}' is hidden by policy",
            session.session_id
        );
        return Ok(());
    }

    // Check exclude_tools
    if config
        .privacy
        .exclude_tools
        .iter()
        .any(|t| t.eq_ignore_ascii_case(&session.agent.tool))
    {
        println!(
            "Skipping upload: tool '{}' is in exclude_tools list",
            session.agent.tool
        );
        return Ok(());
    }

    println!(
        "Parsed session: {} ({} events, {} tool calls)",
        session.session_id, session.stats.event_count, session.stats.tool_call_count
    );

    if use_git {
        return upload_to_git(&session, &daemon_config);
    }

    println!("Uploading to {}...", config.server.url);

    let mut client = ApiClient::new(&config.server.url, Duration::from_secs(60))?;
    if !config.server.api_key.trim().is_empty() {
        client.set_auth(config.server.api_key.clone());
    }

    let linked = if parent_ids.is_empty() {
        None
    } else {
        Some(parent_ids.to_vec())
    };

    let resp = client
        .upload_session(&opensession_api_client::opensession_api::UploadRequest {
            session,
            body_url: None,
            linked_session_ids: linked,
            git_remote: None,
            git_branch: None,
            git_commit: None,
            git_repo_name: None,
            pr_number: None,
            pr_url: None,
            score_plugin: None,
        })
        .await?;

    println!("Upload successful!");
    println!("Session ID: {}", resp.id);

    Ok(())
}

/// Store session to the git branch in the current repo.
fn upload_to_git(
    session: &opensession_core::Session,
    config: &opensession_runtime_config::DaemonConfig,
) -> Result<()> {
    let repo_root = resolve_repo_root_for_session(session);

    let repo_root = match repo_root {
        Some(r) => r,
        None => bail!("Not inside a git repository. Run from a git repo or use server upload."),
    };

    println!(
        "Storing to git-native ledger in {}...",
        repo_root.display()
    );

    let repo_root_owned;
    let cwd = if let Some(cwd) = working_directory(session) {
        cwd
    } else {
        repo_root_owned = repo_root.to_string_lossy().to_string();
        repo_root_owned.as_str()
    };
    let git_ctx = opensession_git_native::extract_git_context(cwd);
    let branch =
        opensession_git_native::resolve_ledger_branch(git_ctx.branch.as_deref(), git_ctx.commit.as_deref());
    let target_ref = opensession_git_native::branch_ledger_ref(&branch);

    let mut sanitized = session.clone();
    let sanitize_config = SanitizeConfig {
        strip_paths: config.privacy.strip_paths,
        strip_env_vars: config.privacy.strip_env_vars,
        exclude_patterns: config.privacy.exclude_patterns.clone(),
    };
    sanitize_session(&mut sanitized, &sanitize_config);

    let hail_jsonl = session_to_hail_jsonl_bytes(&sanitized)?;
    let git_meta = GitMeta {
        remote: git_ctx.remote.clone(),
        repo_name: git_ctx.repo_name.clone(),
        branch: Some(branch),
        head: git_ctx.commit.clone(),
        commits: git_ctx.commit.clone().into_iter().collect(),
    };
    let meta_json = build_git_storage_meta_json_with_git(&sanitized, Some(&git_meta));

    let storage = opensession_git_native::NativeGitStorage;
    let stored = storage
        .store_session_at_ref(
            &repo_root,
            &target_ref,
            &session.session_id,
            &hail_jsonl,
            &meta_json,
            &git_meta.commits,
        )
        .map_err(|e| anyhow::anyhow!("Git storage failed: {e}"))?;

    println!("Stored at: {} (ref: {})", stored.hail_path, stored.ref_name);
    println!("Session ID: {}", session.session_id);

    Ok(())
}

fn resolve_repo_root_for_session(
    session: &opensession_core::Session,
) -> Option<std::path::PathBuf> {
    if let Some(cwd) = working_directory(session) {
        if let Some(repo_root) = opensession_git_native::ops::find_repo_root(Path::new(cwd)) {
            return Some(repo_root);
        }
    }

    std::env::current_dir()
        .ok()
        .and_then(|cwd| opensession_git_native::ops::find_repo_root(&cwd))
}

fn session_to_hail_jsonl_bytes(session: &opensession_core::Session) -> Result<Vec<u8>> {
    session
        .to_jsonl()
        .map(|jsonl| jsonl.into_bytes())
        .map_err(|e| anyhow::anyhow!("failed to serialize HAIL JSONL body: {e}"))
}

#[cfg(test)]
mod tests {
    use super::{resolve_repo_root_for_session, session_to_hail_jsonl_bytes};
    use chrono::Utc;
    use opensession_core::session::ATTR_CWD;
    use opensession_core::{Agent, Content, Event, EventType, Session};
    use std::path::PathBuf;
    use std::sync::{Mutex, OnceLock};
    use tempfile::tempdir;

    fn cwd_test_lock() -> &'static Mutex<()> {
        static LOCK: OnceLock<Mutex<()>> = OnceLock::new();
        LOCK.get_or_init(|| Mutex::new(()))
    }

    struct CwdRestore {
        path: PathBuf,
