    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent)?;
    }
    if !path.exists() {
        std::fs::write(&path, bytes)?;
    }
    Ok(StoredObject {
        uri: SourceUri::Src(SourceSpec::Local {
            sha256: sha256.clone(),
        }),
        sha256,
        path,
        bytes: bytes.len(),
    })
}

