use crate::trace::{Event, EventType, Session, Stats};
use serde::{Deserialize, Serialize};

pub const ATTR_CWD: &str = "cwd";
pub const ATTR_WORKING_DIRECTORY: &str = "working_directory";
pub const ATTR_SOURCE_PATH: &str = "source_path";
pub const ATTR_SESSION_ROLE: &str = "session_role";
pub const ATTR_PARENT_SESSION_ID: &str = "parent_session_id";

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SessionRole {
    Primary,
    Auxiliary,
}

fn attr_non_empty_str<'a>(session: &'a Session, key: &str) -> Option<&'a str> {
    session
        .context
        .attributes
        .get(key)
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
}

pub fn working_directory(session: &Session) -> Option<&str> {
    attr_non_empty_str(session, ATTR_CWD)
        .or_else(|| attr_non_empty_str(session, ATTR_WORKING_DIRECTORY))
}

pub fn source_path(session: &Session) -> Option<&str> {
    attr_non_empty_str(session, ATTR_SOURCE_PATH)
}

pub fn session_role(session: &Session) -> SessionRole {
    if let Some(raw_role) = attr_non_empty_str(session, ATTR_SESSION_ROLE) {
        if raw_role.eq_ignore_ascii_case("auxiliary") {
            return SessionRole::Auxiliary;
        }
        if raw_role.eq_ignore_ascii_case("primary") {
            return SessionRole::Primary;
        }
    }

    if !session.context.related_session_ids.is_empty() {
        return SessionRole::Auxiliary;
    }

    if attr_non_empty_str(session, ATTR_PARENT_SESSION_ID).is_some() {
        return SessionRole::Auxiliary;
    }

    SessionRole::Primary
}

pub fn is_auxiliary_session(session: &Session) -> bool {
    session_role(session) == SessionRole::Auxiliary
}

/// Build an interaction-focused compressed session.
///
/// Only interaction-like events are retained and stats are recomputed.
pub fn interaction_compressed_session(session: &Session) -> Session {
    let mut compressed = session.clone();
    compressed.events.retain(is_interaction_flow_event);
    compressed.recompute_stats();
    compressed
}

/// Build compressed stats by keeping only interaction-focused events.
///
/// This is intended for lightweight local index/cache storage where
/// chronological full fidelity is not required.
pub fn interaction_compressed_stats(session: &Session) -> Stats {
    interaction_compressed_session(session).stats
}

fn is_interaction_flow_event(event: &Event) -> bool {
    if is_interrupt_like_event(event) {
        return true;
    }

    if matches!(
        event.event_type,
        EventType::UserMessage | EventType::AgentMessage
    ) {
        return true;
    }

    if matches!(event.event_type, EventType::SystemMessage)
        && event
            .attr_str("source")
            .is_some_and(|source| source.eq_ignore_ascii_case("interactive_question"))
    {
        return true;
    }

    match &event.event_type {
        EventType::ToolCall { name } | EventType::ToolResult { name, .. } => {
            event
                .semantic_tool_kind()
                .is_some_and(|kind| kind.eq_ignore_ascii_case("interactive"))
                || matches!(
                    name.trim().to_ascii_lowercase().as_str(),
                    "request_user_input" | "ask_followup_question"
                )
        }
        _ => false,
    }
}

fn is_interrupt_like_event(event: &Event) -> bool {
    if let EventType::Custom { kind } = &event.event_type {
        let lowered = kind.trim().to_ascii_lowercase();
        return lowered == "turn_aborted"
            || lowered.contains("interrupt")
            || lowered.contains("aborted");
    }
    false
}

#[derive(Debug, Clone, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct GitMeta {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub remote: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub repo_name: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub branch: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub head: Option<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub commits: Vec<String>,
}

pub fn build_git_storage_meta_json_with_git(session: &Session, git: Option<&GitMeta>) -> Vec<u8> {
    let role = match session_role(session) {
        SessionRole::Primary => "primary",
        SessionRole::Auxiliary => "auxiliary",
    };

    let mut payload = serde_json::json!({
        "schema_version": 2,
        "session_id": session.session_id,
        "title": session.context.title,
        "tool": session.agent.tool,
