        println!("{}", branch_ledger_ref(&branch));
        return Ok(());
    }

    if args.sync_branch_session.is_none() && args.sync_branch_commit.is_some() {
        bail!("--sync-branch-commit requires --sync-branch-session");
    }

    if let Some(branch) = args.sync_branch_session {
