            .ok_or_else(|| anyhow::anyhow!("current directory is not inside a git repository"))?;
        let mode = read_fanout_mode(&repo_root)?.unwrap_or(FanoutMode::HiddenRef);
        println!("{}", mode.as_str());
        return Ok(());
    }

