    let repo_root = opensession_git_native::ops::find_repo_root(&cwd)
        .ok_or_else(|| anyhow::anyhow!("current directory is not inside a git repository"))?;

    validate_setup_args(&args)?;
    if args.check {
        return run_check(&repo_root);
    }
    run_install(
