use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Canonical event attribute key for source schema version.
pub const ATTR_SOURCE_SCHEMA_VERSION: &str = "source.schema_version";
/// Canonical event attribute key for source raw record type.
pub const ATTR_SOURCE_RAW_TYPE: &str = "source.raw_type";
/// Canonical event attribute key for semantic group/turn identifier.
pub const ATTR_SEMANTIC_GROUP_ID: &str = "semantic.group_id";
/// Canonical event attribute key for semantic tool call identifier.
pub const ATTR_SEMANTIC_CALL_ID: &str = "semantic.call_id";
/// Canonical event attribute key for semantic tool kind classification.
pub const ATTR_SEMANTIC_TOOL_KIND: &str = "semantic.tool_kind";

/// Top-level session - the normalized OpenSession trace model.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Session {
    /// Canonical persistence format version, e.g. "acp-semantic-1.0.0"
    pub version: String,
    /// Unique session identifier (UUID)
    pub session_id: String,
    /// AI agent information
    pub agent: Agent,
    /// Session metadata
    pub context: SessionContext,
    /// Flat timeline of events
    pub events: Vec<Event>,
    /// Aggregate statistics
    pub stats: Stats,
}

#[derive(Default)]
struct StatsAcc {
    message_count: u64,
    user_message_count: u64,
    tool_call_count: u64,
    task_ids: std::collections::HashSet<String>,
    total_input_tokens: u64,
    total_output_tokens: u64,
    total_input_tokens_cumulative: Option<u64>,
    total_output_tokens_cumulative: Option<u64>,
    changed_files: std::collections::HashSet<String>,
    lines_added: u64,
    lines_removed: u64,
}

impl StatsAcc {
    fn process(mut self, event: &Event) -> Self {
        match &event.event_type {
            EventType::UserMessage => {
                self.message_count += 1;
                self.user_message_count += 1;
            }
            EventType::AgentMessage => self.message_count += 1,
            EventType::TaskEnd { summary } => {
                if summary
                    .as_deref()
                    .map(str::trim)
                    .is_some_and(|text| !text.is_empty())
                {
                    self.message_count += 1;
                }
            }
            EventType::ToolCall { .. }
            | EventType::FileRead { .. }
            | EventType::CodeSearch { .. }
            | EventType::FileSearch { .. } => self.tool_call_count += 1,
            EventType::FileEdit { path, diff } => {
                self.changed_files.insert(path.clone());
                if let Some(d) = diff {
                    for line in d.lines() {
                        if line.starts_with('+') && !line.starts_with("+++") {
                            self.lines_added += 1;
                        } else if line.starts_with('-') && !line.starts_with("---") {
                            self.lines_removed += 1;
                        }
                    }
                }
            }
            EventType::FileCreate { path } | EventType::FileDelete { path } => {
                self.changed_files.insert(path.clone());
            }
            _ => {}
        }
        if let Some(ref tid) = event.task_id {
            self.task_ids.insert(tid.clone());
        }
        if let Some(v) = event.attributes.get("input_tokens") {
            self.total_input_tokens += v.as_u64().unwrap_or(0);
        }
        if let Some(v) = event.attributes.get("output_tokens") {
            self.total_output_tokens += v.as_u64().unwrap_or(0);
        }
        if let Some(v) = event.attributes.get("input_tokens_total") {
            let value = v.as_u64().unwrap_or(0);
            self.total_input_tokens_cumulative = Some(
                self.total_input_tokens_cumulative
                    .map_or(value, |existing| existing.max(value)),
            );
        }
        if let Some(v) = event.attributes.get("output_tokens_total") {
            let value = v.as_u64().unwrap_or(0);
            self.total_output_tokens_cumulative = Some(
                self.total_output_tokens_cumulative
                    .map_or(value, |existing| existing.max(value)),
            );
        }
        self
    }

    fn into_stats(self, events: &[Event]) -> Stats {
        let duration_seconds = if let (Some(first), Some(last)) = (events.first(), events.last()) {
            (last.timestamp - first.timestamp).num_seconds().max(0) as u64
        } else {
            0
        };

        Stats {
            event_count: events.len() as u64,
            message_count: self.message_count,
            tool_call_count: self.tool_call_count,
            task_count: self.task_ids.len() as u64,
            duration_seconds,
            total_input_tokens: self
                .total_input_tokens_cumulative
                .unwrap_or(self.total_input_tokens),
            total_output_tokens: self
                .total_output_tokens_cumulative
                .unwrap_or(self.total_output_tokens),
            user_message_count: self.user_message_count,
            files_changed: self.changed_files.len() as u64,
            lines_added: self.lines_added,
            lines_removed: self.lines_removed,
        }
    }
}

impl Session {
    pub const CURRENT_VERSION: &'static str = "acp-semantic-1.0.0";

    pub fn new(session_id: String, agent: Agent) -> Self {
        Self {
            version: Self::CURRENT_VERSION.to_string(),
            session_id,
            agent,
            context: SessionContext::default(),
            events: Vec::new(),
            stats: Stats::default(),
        }
    }

    /// Serialize to the canonical ACP semantic JSONL string.
    pub fn to_jsonl(&self) -> Result<String, crate::jsonl::JsonlError> {
        crate::jsonl::to_jsonl_string(self)
    }

    /// Deserialize from either ACP semantic JSONL or legacy HAIL v1 JSONL.
    pub fn from_jsonl(s: &str) -> Result<Self, crate::jsonl::JsonlError> {
        crate::jsonl::from_jsonl_str(s)
    }

    /// Serialize to the canonical ACP semantic JSONL string explicitly.
    pub fn to_acp_semantic_jsonl(&self) -> Result<String, crate::jsonl::JsonlError> {
        crate::jsonl::to_acp_semantic_jsonl_string(self)
    }

    /// Deserialize from ACP semantic JSONL explicitly.
    pub fn from_acp_semantic_jsonl(s: &str) -> Result<Self, crate::jsonl::JsonlError> {
        crate::jsonl::from_acp_semantic_jsonl_str(s)
    }

    /// Serialize to the legacy HAIL v1 header/event/stats JSONL format explicitly.
    pub fn to_hail_v1_jsonl(&self) -> Result<String, crate::jsonl::JsonlError> {
        crate::jsonl::to_hail_v1_jsonl_string(self)
    }

    /// Deserialize from the legacy HAIL v1 header/event/stats JSONL format explicitly.
    pub fn from_hail_v1_jsonl(s: &str) -> Result<Self, crate::jsonl::JsonlError> {
        crate::jsonl::from_hail_v1_jsonl_str(s)
    }

    /// Recompute stats from events
    pub fn recompute_stats(&mut self) {
        let acc = self
            .events
            .iter()
            .fold(StatsAcc::default(), StatsAcc::process);
        self.stats = acc.into_stats(&self.events);
    }
}

/// AI agent information
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Agent {
    /// Provider: "anthropic", "openai", "local"
    pub provider: String,
    /// Model: "claude-opus-4-6", "gpt-4o"
    pub model: String,
    /// Tool: "claude-code", "codex", "cursor"
    pub tool: String,
    /// Tool version
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tool_version: Option<String>,
}

/// Session context metadata
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SessionContext {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub title: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub description: Option<String>,
    #[serde(default)]
    pub tags: Vec<String>,
    pub created_at: DateTime<Utc>,
    pub updated_at: DateTime<Utc>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub related_session_ids: Vec<String>,
    #[serde(default, skip_serializing_if = "HashMap::is_empty")]
    pub attributes: HashMap<String, serde_json::Value>,
}

impl Default for SessionContext {
    fn default() -> Self {
        let now = Utc::now();
        Self {
            title: None,
            description: None,
            tags: Vec::new(),
            created_at: now,
            updated_at: now,
            related_session_ids: Vec::new(),
            attributes: HashMap::new(),
        }
    }
}

/// A single event in the flat timeline
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Event {
    /// Unique event identifier
    pub event_id: String,
    /// When this event occurred
    pub timestamp: DateTime<Utc>,
    /// Type of event
    pub event_type: EventType,
    /// Optional task grouping ID
    #[serde(skip_serializing_if = "Option::is_none")]
    pub task_id: Option<String>,
