+    while candidate_idx < candidate.len() {
+        if pattern_idx < pattern.len() && pattern[pattern_idx] == candidate[candidate_idx] {
+            pattern_idx += 1;
+            candidate_idx += 1;
+            continue;
+        }
+        if pattern_idx < pattern.len() && pattern[pattern_idx] == b'*' {
+            star_idx = Some(pattern_idx);
